refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/baboon.png"));
image = imresize(image, [120 160], "area");
framed = impadarray(image, [10 25 20 35], "constant", 32);

subplot(1, 2, 1);
imshow(image);
xtitle("Original 120 x 160 image");
subplot(1, 2, 2);
imshow(framed);
xtitle("Asymmetric padding: top, bottom, left, right");

patch = uint8([25 75 125; 50 100 150; 75 125 175]);
constantPad = impadarray(patch, 2, "constant", 0);
replicatePad = impadarray(patch, 2, "replicate");
displaySize = [196 196];

subplot(1, 3, 1);
imshow(imresize(patch, displaySize, "nearest"), gray(256));
xtitle("Original 3 x 3 patch");
subplot(1, 3, 2);
imshow(imresize(constantPad, displaySize, "nearest"), gray(256));
xtitle("Constant zero padding");
subplot(1, 3, 3);
imshow(imresize(replicatePad, displaySize, "nearest"), gray(256));
xtitle("Replicated edge padding");
